package prophesy

import scala.quoted.*

import anticipation.*

// The interface through which a `Dynamic` type offers tab completions. The compiler's interactive
// completion engine cannot enumerate the members a `selectDynamic`/`applyDynamic` implementation
// would accept, but a refined receiver type often determines them fully. The companion object of
// the `Dynamic` base type implements this trait; a completion engine (such as Harlequin's) finds
// that companion from the receiver's type at the caret, loads it reflectively in its own JVM, and
// invokes `completions` with a live `Quotes` and the receiver's full (refined) `TypeRepr`.
//
// `prefix` is the partial member name already typed at the caret (possibly empty); implementations
// may use it to filter, but need not вҖ” the engine filters by prefix regardless. Implementations
// must be pure and total: any exception is caught by the engine and treated as "no completions".
trait Completable:
  def completions(using quotes: Quotes)(receiver: quotes.reflect.TypeRepr, prefix: Text)
  :   List[Completion]
